export interface AuthBridge {
    getAccessToken(): string | null | Promise<string | null>;
    getClientId(): string | null | Promise<string | null>;
    refreshAccessToken(): Promise<string>;
    onUnauthorized?: () => void | Promise<void>;
}
export interface RetryPolicy {
    maxAttempts?: number;
    baseDelayMs?: number;
}
export interface PointsClientConfig {
    baseURL: string;
    auth: AuthBridge;
    retry?: RetryPolicy;
    defaultHeaders?: Record<string, string>;
}
export interface HealthStatus {
    status: 'ok' | 'degraded' | 'down';
    version?: string;
    time?: string;
    db?: 'ok' | 'error';
    latencyMs?: number;
}
export interface BalanceResult {
    uid: string;
    balance: number;
}
export interface ConsumeRequest {
    amount: number;
    reason?: string;
    requestId: string;
}
export interface ConsumeResult {
    uid: string;
    amount: number;
    newBalance: number;
    txnId: number;
}
export interface ListConsumptionsQuery {
    limit?: number;
    cursor?: string;
    from?: string;
    to?: string;
}
export interface ListedConsumptionItem {
    id: number;
    uid: string;
    clientId: string;
    amount: number;
    reason?: string;
    newBalance: number;
    createdAt: string;
}
export interface ListConsumptionsResult {
    items: ListedConsumptionItem[];
    nextCursor?: string;
}
